/**
 * Indonesia PEP enhanced due diligence gate (POJK 8/2023 + PPATK Reg. 11/2020).
 *
 * OJK requires enhanced due diligence for all Politically Exposed
 * Persons — domestic, foreign, and international organization PEPs.
 * Senior management sign-off is required before the relationship
 * is established. Source of funds and wealth must be verified.
 *
 * Modeled as BLOCK — the compliance team must complete EDD review
 * and clear the account holder before transactions can proceed.
 * Checks the debtor (sender) side since the AH initiating the
 * transaction is the primary PEP risk.
 */
export const handler = async (input) => {
  const debtor = input.debtor_payment_account;
  if (!debtor) return { ledger_accounts: {} };

  const ah = debtor.account_holder;
  const le = ah && ah.legal_entity;
  if (!le) return { ledger_accounts: {} };

  if (le.politically_exposed_person !== true) return { ledger_accounts: {} };

  const las = debtor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'id_pep_edd',
      block_reason: 'id_pep_edd',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
